from typing import Dict, List, Optional
from dataclasses import dataclass

@dataclass
class Block:
    height: int
    hash: str
    parent_hash: str
    proposer: str

class SafetyChecker:
    def __init__(self):
        # Track committed blocks per height
        self.committed: Dict[int, List[Block]] = {}

    def commit_block(self, node_id: str, block: Block) -> bool:
        """Record a block commitment and check safety."""
        height = block.height

        if height not in self.committed:
            self.committed[height] = []

        # Check if conflicting block already committed
        for existing in self.committed[height]:
            if existing.hash != block.hash:
                print(f"SAFETY VIOLATION!")
                print(f"Node {node_id} committing {block.hash}")
                print(f"But {existing.hash} already committed at height {height}")
                return False

        self.committed[height].append(block)
        print(f"Node {node_id} safely committed {block.hash[:8]} at height {height}")
        return True

    def verify_chain_safety(self, chain: List[Block]) -> bool:
        """Verify no conflicting blocks in the chain."""
        blocks_at_height: Dict[int, set] = {}

        for block in chain:
            if block.height not in blocks_at_height:
                blocks_at_height[block.height] = set()
            blocks_at_height[block.height].add(block.hash)

        for height, hashes in blocks_at_height.items():
            if len(hashes) > 1:
                print(f"Safety violation at height {height}: {hashes}")
                return False

        print("Chain passes safety check")
        return True

# Example usage
checker = SafetyChecker()

block1 = Block(1, "0xabc", "0x000", "node1")
block2 = Block(1, "0xdef", "0x000", "node2")  # Conflicting!

checker.commit_block("node_a", block1)  # OK
checker.commit_block("node_b", block2)  # VIOLATION!

class TrilemmaAnalyzer {
    constructor(blockchain) {
        this.name = blockchain.name;
        this.decentralization = blockchain.decentralization; // 0-100
        this.security = blockchain.security; // 0-100
        this.scalability = blockchain.scalability; // 0-100
    }

    analyze() {
        console.log(`\n=== ${this.name} Trilemma Analysis ===");

        // Calculate trilemma score (can't have all three high)
        const total = this.decentralization + this.security + this.scalability;
        const maxPossible = 200; // Theoretical max with trilemma

        if (total > maxPossible) {
            console.log('Warning: Claims may be optimistic (exceeds trilemma limit)');
        }

        // Identify strongest and weakest
        const scores = [
            { name: 'Decentralization', score: this.decentralization },
            { name: 'Security', score: this.security },
            { name: 'Scalability', score: this.scalability }
        ].sort((a, b) => b.score - a.score);

        console.log(`Strongest: ${scores[0].name} (${scores[0].score})`);
        console.log(`Weakest: ${scores[2].name} (${scores[2].score})`);

        // Suggest use cases
        this.suggestUseCases(scores);
    }

    suggestUseCases(scores) {
        const strongest = scores[0].name;
        const second = scores[1].name;

        const useCases = {
            'Decentralization+Security': 'Store of value, censorship-resistant apps',
            'Security+Scalability': 'Enterprise blockchain, private networks',
            'Decentralization+Scalability': 'Consumer dApps, gaming'
        };

        const key = `${strongest}+${second}`;
        console.log(`\nSuggested use cases: ${useCases[key] || 'General purpose'}`);
    }
}

