package main

import "fmt"

type Validator struct {
    Address string
    Stake   uint64
}

type SybilResistantNetwork struct {
    validators    []Validator
    totalStake    uint64
    minStake      uint64
}

func NewNetwork(minStake uint64) *SybilResistantNetwork {
    return &SybilResistantNetwork{
        validators: []Validator{},
        minStake:   minStake,
    }
}

func (n *SybilResistantNetwork) RegisterValidator(addr string, stake uint64) error {
    if stake < n.minStake {
        return fmt.Errorf("stake %d below minimum %d", stake, n.minStake)
    }

    n.validators = append(n.validators, Validator{addr, stake})
    n.totalStake += stake
    fmt.Printf("Registered validator %s with stake %d\n", addr, stake)
    return nil
}

func (n *SybilResistantNetwork) GetVotingPower(addr string) float64 {
    for _, v := range n.validators {
        if v.Address == addr {
            return float64(v.Stake) / float64(n.totalStake) * 100
        }
    }
    return 0
}

func (n *SybilResistantNetwork) SimulateSybilAttack(attackerStake uint64, fakeIdentities int) {
    fmt.Printf("\n=== Sybil Attack Simulation ===")
    fmt.Printf("Attacker total stake: %d\n", attackerStake)
    fmt.Printf("Fake identities: %d\n", fakeIdentities)

    stakePerIdentity := attackerStake / uint64(fakeIdentities)
    fmt.Printf("Stake per identity: %d\n", stakePerIdentity)

    // Even with many identities, total power = total stake
    totalAttackerPower := float64(attackerStake) / float64(n.totalStake+attackerStake) * 100
    fmt.Printf("\nTotal attacker voting power: %.2f%%\n", totalAttackerPower)
    fmt.Println("Creating multiple identities doesn't increase power!")
}

func main() {
    network := NewNetwork(1000) // Min 1000 tokens to validate

    // Register honest validators
    network.RegisterValidator("honest1", 50000)
    network.RegisterValidator("honest2", 30000)
    network.RegisterValidator("honest3", 20000)

    fmt.Printf("\nHonest1 power: %.2f%%\n", network.GetVotingPower("honest1"))

    // Attacker tries Sybil with 10000 tokens split into 10 identities
    network.SimulateSybilAttack(10000, 10)
}
